() => {
  // Look for comment count indicators
  const header = document.querySelector('[data-testid="issue-comment-count"]');
  if (header) return header.textContent;

  // Try to find the total comments from the page
  const allText = document.body.innerText;
  const match = allText.match(/(\d+) comments/);
  return match ? match[0] : 'not found';
}

